/**
 * OPTIMIZATION STAGE 1: SQL-Based Pre-filtering
 * This runs fast SQL queries to eliminate obvious mismatches
 * Reduces dataset by 70-80%
 */

const users = $('Fetch New Users').all();
const products = $('Fetch Loan Products').all();

const preFilteredPairs = [];

// Cross-join with SQL-like filtering in JavaScript
for (const userItem of users) {
  const user = userItem.json;

  for (const productItem of products) {
    const product = productItem.json;

    // Fast numeric comparisons (Stage 1)
    if (user.monthly_income >= product.min_income &&
        user.credit_score >= product.min_credit_score &&
        user.age >= product.min_age &&
        user.age <= (product.max_age || 100)) {

      preFilteredPairs.push({
        json: {
          user_id: user.user_id,
          product_id: product.product_id,
          user: user,
          product: product,
          stage: 'pre-filtered'
        }
      });
    }
  }
}

console.log(`Stage 1 (SQL Pre-filter): ${users.length} users × ${products.length} products = ${users.length * products.length} total`);
console.log(`After pre-filtering: ${preFilteredPairs.length} potential matches (${((preFilteredPairs.length / (users.length * products.length)) * 100).toFixed(1)}%)`);

return preFilteredPairs;

/**
 * OPTIMIZATION STAGE 2: Business Rules Filtering
 * Apply complex eligibility rules
 * Further reduces by 15-20%
 */

const pair = $input.item.json;
const user = pair.user;
const product = pair.product;

// Business rules checks
const rules = {
  employment_valid: true,
  income_ratio_valid: true,
  credit_tier_match: true
};

// Employment status validation
const validEmploymentStatuses = ['full-time', 'self-employed', 'part-time'];
if (!validEmploymentStatuses.includes(user.employment_status.toLowerCase())) {
  rules.employment_valid = false;
}

// Income-to-loan ratio (if max_loan_amount exists)
if (product.max_loan_amount) {
  const monthlyPayment = product.max_loan_amount / 60; // Simplified
  const debtToIncomeRatio = (monthlyPayment / user.monthly_income);

  if (debtToIncomeRatio > 0.43) { // Max DTI ratio
    rules.income_ratio_valid = false;
  }
}

// Credit score tier matching
if (user.credit_score < 700 && product.interest_rate < 7.0) {
  // High-tier products unlikely for lower credit scores
  rules.credit_tier_match = false;
}

// Calculate match score based on how well user exceeds minimum requirements
let matchScore = 0;

if (Object.values(rules).every(r => r)) {
  // Income score (0-0.3)
  const incomeExcess = (user.monthly_income - product.min_income) / product.min_income;
  const incomeScore = Math.min(incomeExcess * 0.3, 0.3);

  // Credit score (0-0.5)
  const creditExcess = (user.credit_score - product.min_credit_score) / (850 - product.min_credit_score);
  const creditScore = creditExcess * 0.5;

  // Interest rate (0-0.2) - lower is better
  const rateScore = (20 - Math.min(product.interest_rate, 20)) / 20 * 0.2;

  matchScore = Math.min(incomeScore + creditScore + rateScore, 1.0);
}

// Only pass matches with score > 0.3
if (matchScore >= 0.3) {
  return [{
    json: {
      user_id: user.user_id,
      product_id: product.product_id,
      user: user,
      product: product,
      match_score: Math.round(matchScore * 100) / 100,
      rules_passed: rules,
      stage: 'business-filtered'
    }
  }];
}

return [];

