// Parse AI response
const response = $input.item.json;
const aiText = response.candidates?.[0]?.content?.parts?.[0]?.text || '';

const isQualified = aiText.toUpperCase().includes('YES');

if (isQualified) {
  const originalData = $node['Ambiguous Case?'].json;
  return [{
    json: {
      ...originalData,
      match_score: Math.min(originalData.match_score + 0.1, 0.99),
      ai_verified: true,
      ai_reason: aiText,
      stage: 'ai-verified'
    }
  }];
}

return [];

// Trigger notification workflow
const matchCount = $input.all().length;
const uniqueUsers = [...new Set($input.all().map(item => item.json.user_id))];

console.log(`User-Loan Matching completed`);
console.log(`Total matches: ${matchCount}`);
console.log(`Users matched: ${uniqueUsers.length}`);

return [{
  json: {
    success: true,
    matches_count: matchCount,
    users_matched: uniqueUsers.length,
    timestamp: new Date().toISOString(),
    trigger_notifications: true
  }
}];
